class Solution:
    def checkSubarraySum(self, nums: List[int], k: int) -> bool:
        rem_idx = {0: -1}
        s = 0
        for i, x in enumerate(nums):
            s += x
            r = s % k if k else s
            if r in rem_idx:
                if i - rem_idx[r] >= 2:
                    return True
            else:
                rem_idx[r] = i
        return False

