class Solution {
public:
    bool checkSubarraySum(vector<int>& nums, int k) {
        unordered_map<int,int> remIdx{{0,-1}};
        long long s = 0;
        for (int i = 0; i < (int)nums.size(); i++) {
            s += nums[i];
            int r = k ? s % k : (int)s;
            if (remIdx.count(r)) {
                if (i - remIdx[r] >= 2) return true;
            } else remIdx[r] = i;
        }
        return false;
    }
};
